#include <stdio.h>
#include <math.h>

int main(void) {
    double x[4], y[4];
    double a, b, c, s, area = 0.0;

    // Read coordinates of 4 points
    for (int i = 0; i < 4; i++) scanf("%lf %lf", &x[i], &y[i]);

    // Generate all combinations of 3 points
    for (int i = 0; i < 3; i++) {
        for (int j = i + 1; j < 4; j++) {
            for (int k = j + 1; k < 4; k++) {
                // Calculate the lengths of the sides of the triangle
                a = sqrt(pow(x[j] - x[i], 2) + pow(y[j] - y[i], 2));
                b = sqrt(pow(x[k] - x[j], 2) + pow(y[k] - y[j], 2));
                c = sqrt(pow(x[i] - x[k], 2) + pow(y[i] - y[k], 2));

                // Check if the points are collinear
                if (a + b <= c || a + c <= b || b + c <= a) {
                    printf("collinear\n");
                    continue;
                }

                // Calculate the semi-perimeter of the triangle
                s = (a + b + c) / 2.0;

                // Calculate the area using Heron's formula
                area = sqrt(s * (s - a) * (s - b) * (s - c));

                // Display the area if the triangle can be formed
                printf("area %.3f\n", area);
            }
        }
    }

    return 0;
}
